#!/usr/bin/env python3
"""Predict script for exploration task - improved planner v4."""
import argparse
import json
import os
import sys
import numpy as np
from collections import deque
from cogniplan_env import ExplorationEnv


def bfs_path(nodes, start_coords, goal_coords):
    """BFS through graph to find path from start to goal node."""
    node_map = {}
    for n in nodes:
        k = (round(float(n['coords'][0]), 1), round(float(n['coords'][1]), 1))
        node_map[k] = n

    start = (round(float(start_coords[0]), 1), round(float(start_coords[1]), 1))
    goal = (round(float(goal_coords[0]), 1), round(float(goal_coords[1]), 1))

    if start == goal:
        return []

    queue = deque([(start, [])])
    visited = {start}

    while queue:
        current, path = queue.popleft()
        node = node_map.get(current)
        if node is None:
            continue
        for neighbor_coords in node.get('neighbors', []):
            nc = (round(float(neighbor_coords[0]), 1), round(float(neighbor_coords[1]), 1))
            new_path = path + [neighbor_coords]
            if nc == goal:
                return new_path
            if nc not in visited:
                visited.add(nc)
                queue.append((nc, new_path))
    return None


def get_frontier_targets(global_map, robot_pos, cell_size=0.4):
    """Find frontier cells and cluster them."""
    UNKNOWN = 127
    FREE = 255
    h, w = global_map.shape
    rx, ry = float(robot_pos[0]), float(robot_pos[1])

    frontier_cells = []
    step = 3
    for r in range(step, h-step, step):
        for c in range(step, w-step, step):
            if global_map[r, c] == UNKNOWN:
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc2 = r+dr, c+dc
                    if 0 <= nr < h and 0 <= nc2 < w and global_map[nr, nc2] == FREE:
                        frontier_cells.append((c * cell_size, r * cell_size))
                        break

    if not frontier_cells:
        return []

    cluster_size = 15.0
    clusters = {}
    for fx, fy in frontier_cells:
        key = (int(fx / cluster_size), int(fy / cluster_size))
        if key not in clusters:
            clusters[key] = []
        clusters[key].append((fx, fy))

    results = []
    for pts in clusters.values():
        cx = float(np.mean([p[0] for p in pts]))
        cy = float(np.mean([p[1] for p in pts]))
        count = len(pts)
        dist = float(np.sqrt((cx - rx)**2 + (cy - ry)**2))
        score = count / max(1.0, dist * 0.1)
        results.append((cx, cy, count, score))

    results.sort(key=lambda x: -x[3])
    return [(r[0], r[1]) for r in results[:8]]


def compute_node_score(node, robot_pos, visit_counts):
    """Compute a score for selecting a node as next target."""
    coords = node['coords']
    utility = float(node.get('utility', 0))
    nx, ny = float(coords[0]), float(coords[1])
    rx, ry = float(robot_pos[0]), float(robot_pos[1])
    dist = float(np.sqrt((nx - rx)**2 + (ny - ry)**2))
    key = (round(nx, 1), round(ny, 1))
    visit_count = visit_counts.get(key, 0)

    score = utility * 10.0
    score -= visit_count * 15.0
    score -= dist * 0.3
    if not node.get('visited', False) and visit_count == 0:
        score += 20.0
    return score


def run_episode(map_path):
    """Run one exploration episode and return metrics."""
    try:
        env = ExplorationEnv(map_path=map_path)
        obs = env.reset()
    except Exception as e:
        print(f"ERROR loading map {map_path}: {e}", file=sys.stderr)
        return None

    visit_counts = {}
    path_queue = []  # Planned path to follow

    for step in range(128):
        nodes = obs.get('nodes', [])
        neighbors = obs.get('neighbors', [])
        robot_pos = obs['robot_pos']
        global_map = obs['global_map']

        if not neighbors:
            break

        # Build node lookup
        nodes_by_key = {}
        for n in nodes:
            k = (round(float(n['coords'][0]), 1), round(float(n['coords'][1]), 1))
            nodes_by_key[k] = n

        # Update visit count for current position
        rk = (round(float(robot_pos[0]), 1), round(float(robot_pos[1]), 1))
        visit_counts[rk] = visit_counts.get(rk, 0) + 1

        # Check if we have a valid path to follow
        if path_queue:
            next_target = path_queue[0]
            nt_key = (round(float(next_target[0]), 1), round(float(next_target[1]), 1))
            # Check if next_target is reachable from current neighbors
            neighbor_keys = [(round(float(nb[0]), 1), round(float(nb[1]), 1)) for nb in neighbors]
            if nt_key in neighbor_keys:
                path_queue.pop(0)
                target = next_target
                obs, info = env.step(target)
                if info.get('done', False):
                    break
                continue
            else:
                # Path is invalid, clear it
                path_queue = []

        # Score all neighbors
        neighbor_scores = []
        for nb in neighbors:
            nb_key = (round(float(nb[0]), 1), round(float(nb[1]), 1))
            nb_node = nodes_by_key.get(nb_key)
            if nb_node is None:
                nb_node = {'coords': nb, 'utility': 0, 'visited': True, 'neighbors': []}
            score = compute_node_score(nb_node, robot_pos, visit_counts)
            neighbor_scores.append((score, nb))

        neighbor_scores.sort(key=lambda x: -x[0])
        best_score, best_neighbor = neighbor_scores[0]

        # If best neighbor has good utility, go there
        if best_score > -10:
            target = best_neighbor
        else:
            # All neighbors are poor - find best global node via BFS
            # First try frontier-based navigation
            frontier_targets = get_frontier_targets(global_map, robot_pos)

            # Find best unvisited/high-utility node globally
            best_global = None
            best_global_score = float('-inf')
            for n in nodes:
                nc = n['coords']
                nk = (round(float(nc[0]), 1), round(float(nc[1]), 1))
                if nk == rk:
                    continue
                score = compute_node_score(n, robot_pos, visit_counts)
                # Bonus for nodes near frontiers
                if frontier_targets:
                    ft = frontier_targets[0]
                    fdist = float(np.sqrt((float(nc[0])-ft[0])**2 + (float(nc[1])-ft[1])**2))
                    score += max(0, 30.0 - fdist * 0.5)
                if score > best_global_score:
                    best_global_score = score
                    best_global = n

            if best_global is not None:
                # BFS path to best global node
                path = bfs_path(nodes, robot_pos, best_global['coords'])
                if path and len(path) > 0:
                    path_queue = list(path)
                    # Take first step
                    next_target = path_queue.pop(0)
                    nt_key = (round(float(next_target[0]), 1), round(float(next_target[1]), 1))
                    neighbor_keys = [(round(float(nb[0]), 1), round(float(nb[1]), 1)) for nb in neighbors]
                    if nt_key in neighbor_keys:
                        target = next_target
                    else:
                        target = best_neighbor
                        path_queue = []
                else:
                    target = best_neighbor
            else:
                target = best_neighbor

        obs, info = env.step(target)
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return metrics


def get_env_type_from_path(map_path):
    """Determine environment type from path."""
    path_lower = map_path.lower()
    if 'room' in path_lower:
        return 'room'
    elif 'tunnel' in path_lower:
        return 'tunnel'
    elif 'outdoor' in path_lower:
        return 'outdoor'
    return 'unknown'


def collect_map_paths(data_path):
    """Collect all map paths from data_path.
    Tries eval_config.json first, then scans maps_eval/ directory.
    Returns list of (map_path, env_type, relative_path) tuples.
    """
    maps = []

    # Try eval_config.json
    config_path = os.path.join(data_path, 'eval_config.json')
    if os.path.exists(config_path):
        try:
            with open(config_path, 'r') as f:
                config = json.load(f)
            print(f"eval_config.json keys: {list(config.keys())}", file=sys.stderr)

            # Try different formats
            if 'episodes' in config:
                for ep in config['episodes']:
                    rel_path = ep.get('map_path', ep.get('map', ''))
                    env_type = ep.get('env_type', ep.get('type', get_env_type_from_path(rel_path)))
                    full_path = os.path.join(data_path, rel_path) if not os.path.isabs(rel_path) else rel_path
                    if not os.path.exists(full_path):
                        full_path = os.path.join(data_path, 'maps_eval', rel_path)
                    maps.append((full_path, env_type, rel_path))
                if maps:
                    return maps

            if 'maps' in config:
                for item in config['maps']:
                    if isinstance(item, dict):
                        rel_path = item.get('path', item.get('map_path', ''))
                        env_type = item.get('env_type', item.get('type', get_env_type_from_path(rel_path)))
                    else:
                        rel_path = item
                        env_type = get_env_type_from_path(rel_path)
                    full_path = os.path.join(data_path, rel_path) if not os.path.isabs(rel_path) else rel_path
                    if not os.path.exists(full_path):
                        full_path = os.path.join(data_path, 'maps_eval', rel_path)
                    maps.append((full_path, env_type, rel_path))
                if maps:
                    return maps

            # Try env_types with map lists
            for env_type in ['room', 'tunnel', 'outdoor']:
                if env_type in config:
                    type_data = config[env_type]
                    if isinstance(type_data, list):
                        for rel_path in type_data:
                            full_path = os.path.join(data_path, rel_path) if not os.path.isabs(rel_path) else rel_path
                            if not os.path.exists(full_path):
                                full_path = os.path.join(data_path, 'maps_eval', rel_path)
                            maps.append((full_path, env_type, rel_path))
            if maps:
                return maps

        except Exception as e:
            print(f"Error reading eval_config.json: {e}", file=sys.stderr)

    # Fall back to scanning maps_eval/ directory
    maps_eval_dir = os.path.join(data_path, 'maps_eval')
    if os.path.exists(maps_eval_dir):
        for env_type in ['room', 'tunnel', 'outdoor']:
            type_dir = os.path.join(maps_eval_dir, env_type)
            if os.path.exists(type_dir):
                for fname in sorted(os.listdir(type_dir)):
                    if fname.endswith('.png'):
                        full_path = os.path.join(type_dir, fname)
                        rel_path = os.path.join(env_type, fname)
                        maps.append((full_path, env_type, rel_path))

    return maps


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    print(f"data_path={args.data_path}", file=sys.stderr)
    print(f"Contents: {os.listdir(args.data_path)}", file=sys.stderr)

    # Collect maps
    maps = collect_map_paths(args.data_path)
    print(f"Found {len(maps)} maps", file=sys.stderr)

    if not maps:
        print("ERROR: No maps found!", file=sys.stderr)
        # Write empty result
        result = {
            "explored_rate": 0.0,
            "travel_distance": 0.0,
            "success_rate": 0.0,
            "per_episode": [],
            "per_type": {},
            "total_episodes": 0
        }
        with open(args.output, 'w') as f:
            json.dump(result, f)
        return

    per_episode = []
    type_results = {'room': [], 'tunnel': [], 'outdoor': [], 'unknown': []}

    for i, (map_path, env_type, rel_path) in enumerate(maps):
        if i % 10 == 0:
            print(f"Progress: {i}/{len(maps)}", file=sys.stderr)

        metrics = run_episode(map_path)
        if metrics is None:
            metrics = {'explored_rate': 0.0, 'travel_distance': 0.0, 'success': False}

        success = 1 if metrics.get('success', False) else 0
        ep_result = {
            'map_path': rel_path,
            'env_type': env_type,
            'success': success,
            'travel_distance': float(metrics.get('travel_distance', 0.0)),
            'explored_rate': float(metrics.get('explored_rate', 0.0))
        }
        per_episode.append(ep_result)
        type_results[env_type].append(ep_result)

    # Compute aggregates
    total = len(per_episode)
    if total == 0:
        result = {
            "explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0,
            "per_episode": [], "per_type": {}, "total_episodes": 0
        }
    else:
        mean_explored = float(np.mean([e['explored_rate'] for e in per_episode]))
        success_eps = [e for e in per_episode if e['success'] == 1]
        mean_dist = float(np.mean([e['travel_distance'] for e in success_eps])) if success_eps else 0.0
        success_rate = float(len(success_eps) / total)

        per_type = {}
        for et in ['room', 'tunnel', 'outdoor']:
            eps = type_results[et]
            if eps:
                s_eps = [e for e in eps if e['success'] == 1]
                per_type[et] = {
                    'explored_rate': float(np.mean([e['explored_rate'] for e in eps])),
                    'travel_distance': float(np.mean([e['travel_distance'] for e in s_eps])) if s_eps else 0.0,
                    'success_rate': float(len(s_eps) / len(eps))
                }

        result = {
            "explored_rate": mean_explored,
            "travel_distance": mean_dist,
            "success_rate": success_rate,
            "per_episode": per_episode,
            "per_type": per_type,
            "total_episodes": total
        }

    with open(args.output, 'w') as f:
        json.dump(result, f, indent=2)

    print(f"Done: {total} episodes, success_rate={result['success_rate']:.3f}", file=sys.stderr)


if __name__ == '__main__':
    main()
